import json
from collections import defaultdict, deque, Counter
d=json.load(open('.leandag/dag.json'))
nodes={n['id']:n for n in d['nodes']}
deps=defaultdict(set); users=defaultdict(set)
for e in d['edges']:
    deps[e['to']].add(e['from']); users[e['from']].add(e['to'])
def clo(start):
    q=deque([start]); s={start}
    while q:
        x=q.popleft()
        for y in deps[x]:
            if y not in s: s.add(y); q.append(y)
    return s
allgoal=set()
for g in ['def:Jacobian','thm:exists_unique_ofCurve_comp','thm:nonempty_jacobianWitness',
          'def:JacobianWitness','def:ofCurve','thm:Jacobian_proper','thm:Jacobian_smooth_genus',
          'thm:Jacobian_grpObj','thm:Jacobian_geomIrred','def:genus','def:IsAlbanese']:
    if g in nodes: allgoal|=clo(g)
outside=[n for n in nodes if not n.startswith('lean:') and n not in allgoal]
# chapter distribution
ch=Counter(nodes[n]['chapter'] or '(none)' for n in outside)
print("=== outside-goal-cone blueprint nodes by chapter (597 total) ===")
for c,k in ch.most_common(): print(f"  {k:4d}  {c}")
# apex = outside nodes that NO node uses (users empty) -> top consumers / cluster roots
print("\n=== APEX outside nodes (nothing \\uses them) — candidate wire-up points ===")
apex=[n for n in outside if len(users[n])==0]
apexch=defaultdict(list)
for n in apex: apexch[nodes[n]['chapter'] or '(none)'].append(n)
for c in sorted(apexch, key=lambda c:-len(apexch[c])):
    print(f"  [{c}] ({len(apexch[c])} apex)")
    for n in apexch[c][:6]: print("       ", n)
